   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag4.png$$, $$Geef de vergelijking van de omzetting van cadmiumgeel tot cadmiumsulfaatmonohydraat.$$, array['367ef2b6-3c1e-4c00-8c65-7bd1f19f484e']::uuid[]),
  ('93482d7a-71d1-4c81-9213-bd815caf6a03', 'a5f1f157-7d19-458e-a0aa-e5e7f09d80a5', 5,
